  ('pukao-d0d1b9a2-moex-00144', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-112-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '作業基礎管理（activity-basedmanagement）較不會運用於下列何種決策？', '["降低成本（reducingcosts）", "改善流程（improvingprocess）", "平穩化成本（smoothingcosts）", "產品訂價與組合（pricingandproductmix）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "22f50c305395", "answer_pdf_sha1": "6a0aa6331aeb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "413", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00145', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-112-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '甲公司採用分批成本制處理相關交易。本年度相關資料如下： 批次編號 批次起始日 批次完工日 7月1日的在製品餘額 7月當月投入的生產成本 #001 6月1日 7月15日 $32,840 $43,600 #002 6月3日 8月25日 $18,100 $177,200 #003 7月2日 7月30日 $145,000 #004 7月6日 7月31日 $82,800 #005 7月5日 8月19日 $126,400 下列何者為該公司7月31日在製品的餘額？', '["$466,700", "$448,600", "$321,700", "$303,600"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "22f50c305395", "answer_pdf_sha1": "6a0aa6331aeb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "413", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00146', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-112-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '關於成本制度的敘述，下列何者錯誤？', '["分批成本制度適用於訂單式生產", "分步成本制度適用於連續性生產", "分步成本制度不可與標準成本制度合用", "分批成本制度可與標準成本制度合用，以利成本控制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "22f50c305395", "answer_pdf_sha1": "6a0aa6331aeb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "413", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00147', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-112-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '乙公司生產並銷售芒果和鳳梨罐頭，X5年度營運資料如下：芒果罐頭預計單位售價$34，預計單 位成本$22，預計銷售量為60,000罐。芒果罐頭實際單位售價$35，實際單位成本$25，實際銷售量 為50,000罐。鳳梨罐頭預計單位售價$37，預計單位成本$21，預計銷售量為60,000罐。鳳梨罐頭實 際單位售價$36，實際單位成本$20，實際銷售量為60,000罐。X5年度，水果罐頭產業產銷芒果罐 頭300,000罐，鳳梨罐頭900,000罐，乙公司預估芒果罐頭的市場總需求為325,000罐，鳳梨罐頭則 為1,175,000罐。下列敘述何者正確？', '["二種水果罐頭預計的市場占有率為8%", "二種水果罐頭的銷售組合差異合計數為$140,000（不利）", "二種水果罐頭的銷售組合差異合計數為$140,000（有利）", "以銷貨毛利差異觀點分析下之市場規模差異為$336,000（有利）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "22f50c305395", "answer_pdf_sha1": "6a0aa6331aeb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "413", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00148', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-112-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '有關直接人工工資率差異之計算公式，下列何者正確？', '["標準工資率 （實際工時－實際產量下之標準工時）", "實際工資率 （實際工時－實際產量下之標準工時） ×", "標準工時 （實際工資率－標準工資率） ×", "實際工時 （實際工資率－標準工資率） ×"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "22f50c305395", "answer_pdf_sha1": "6a0aa6331aeb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "413", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00149', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-112-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '丁公司原料每磅實際單價$8，標準單價$10。若產品的原料實際使用量大於標準使用量，下列敘述 × 何者正確？', '["原料數量差異為不利，原料價格差異為有利", "原料數量差異為有利，原料價格差異為有利", "原料數量差異為有利，原料價格差異為不利", "原料數量差異為不利，原料價格差異為不利"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "22f50c305395", "answer_pdf_sha1": "6a0aa6331aeb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "413", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00150', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-112-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '甲公司為印表機銷售公司，X2年年初針對未來各季的銷售預測分別為$15,000、$20,000、$40,000 及$25,000，該公司每一季之銷售中的80%於當季收到現金，其餘20%於下一季收到現金。另外， X1年年底之應收帳款$5,000可於X2年第一季收現，下列何者為X2年現金收入預算之總額？', '["$90,000", "$100,000", "$110,000", "$120,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "22f50c305395", "answer_pdf_sha1": "6a0aa6331aeb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "413", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00151', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-112-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '甲公司本月份進行直接人工成本差異分析，總共實際發生薪資$252,000，不利之直接人工工資率 差異$36,000，有利之直接人工效率差異$24,000，下列何者不會呈現在期中各項差異之分錄中？', '["借記：在製品$240,000", "借記：直接人工工資率差異$36,000", "借記：直接人工效率差異$24,000", "貸記：應付薪資$252,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "22f50c305395", "answer_pdf_sha1": "6a0aa6331aeb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "413", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00152', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-112-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '下列關於攸關成本之敘述，何者正確？', '["變動成本係隨方案不同而變動之成本，故所有變動成本皆為攸關成本", "固定成本係不隨方案而變動之成本，故所有固定成本皆為非攸關成本", "不可免成本係無法隨方案不同而節省之成本，故所有不可免成本皆為攸關成本", "攸關成本係影響決策之成本，故兩方案間具差異之未來成本屬於攸關成本"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "22f50c305395", "answer_pdf_sha1": "6a0aa6331aeb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "413", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00153', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-112-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '甲公司以每張$200販售遊戲卡，其競爭廠商出售相同商品之售價為$170。經市調後發現若公司將遊 戲卡之售價降至與競爭廠商相同，將使公司的銷售量增加10%。目前甲公司製造遊戲卡之相關成本為 $130，目標毛利率為30%。若以競爭廠商之售價為出售遊戲卡之目標價格，下列敘述何者正確？', '["成本必須減少$11", "成本必須減少$27", "成本必須減少$39", "成本沒影響"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "22f50c305395", "answer_pdf_sha1": "6a0aa6331aeb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "413", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL)
